import{_ as t,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G05: 營收模式與收費策略 - 產品經理 (L3-PM) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3135_凌航/20260430/G05_營收模式與收費策略_產品經理.md","filePath":"審計報告庫/經營審計/3135_凌航/20260430/G05_營收模式與收費策略_產品經理.md"}'),r={name:"審計報告庫/經營審計/3135_凌航/20260430/G05_營收模式與收費策略_產品經理.md"};function e(n,a,s,h,c,d){return i(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="g05-營收模式與收費策略-產品經理-l3-pm-審計報告" tabindex="-1">G05: 營收模式與收費策略 - 產品經理 (L3-PM) 審計報告 <a class="header-anchor" href="#g05-營收模式與收費策略-產品經理-l3-pm-審計報告" aria-label="Permalink to &quot;G05: 營收模式與收費策略 - 產品經理 (L3-PM) 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司的主要營收模式與收費策略為何？其獲利的穩定性與可預測性如何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：純買斷銷售，零經常性收入。MoM波動30.3%，營收依賴記憶體報價。2025年+135%乃漲價驅動，報價反轉即腰斬。</li><li><strong>風險評級</strong>：高</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>經常性收益</strong>：0%（純產品銷售，無訂閱/權利金/維運）</li><li><strong>MoM 波動率</strong>：30.3%</li><li><strong>毛利率</strong>：3.6%（Q2）→ 19.12%（Q4），波動 15.5pp</li><li><strong>2025 營收</strong>：77.04 億（YoY +135%）</li><li><strong>2026 Q1</strong>：39.58 億（YoY +178%）</li><li><strong>診斷</strong>：漲價紅利非結構成長，毛利率吻合DRAM報價曲線，無自主定價權。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、營收模式" tabindex="-1">一、營收模式 <a class="header-anchor" href="#一、營收模式" aria-label="Permalink to &quot;一、營收模式&quot;">​</a></h3><ul><li><strong>模式</strong>：純買斷銷售（DRAM 68%、Flash/SSD 31%）+ ODM代工，零經常性收入。客群：SI/B2G 47%、電競 46%、工控 7%。</li><li><strong>見解</strong>：每月營收從零爭取，47%標案收入具一次性特質，防禦力近零。</li></ul><h3 id="二、定價權" tabindex="-1">二、定價權 <a class="header-anchor" href="#二、定價權" aria-label="Permalink to &quot;二、定價權&quot;">​</a></h3><ul><li><strong>邏輯</strong>：原廠IC成本 + 加工附加。工控僅佔7-8%，主流模組佔60%+為標準品。</li><li><strong>見解</strong>：毛利率3.6%→19.12%的劇烈波動，印證「傳聲筒」成本結構，無自主定價權。</li></ul><h3 id="三、穩定性" tabindex="-1">三、穩定性 <a class="header-anchor" href="#三、穩定性" aria-label="Permalink to &quot;三、穩定性&quot;">​</a></h3><ul><li><strong>數據</strong>：月營收MoM波動30.3%，振幅3倍（5.41億~15.46億）。</li><li><strong>見解</strong>：記憶體現貨價波動 + B2G標案集中出貨，屬上市櫃極端值。</li></ul><h3 id="四、毛利率韌性" tabindex="-1">四、毛利率韌性 <a class="header-anchor" href="#四、毛利率韌性" aria-label="Permalink to &quot;四、毛利率韌性&quot;">​</a></h3><ul><li><strong>數據</strong>：2024全年4.48%→2025H1壓縮至4.25%，Q2虧損（-946.5萬），Q4才跳升至19.12%。</li><li><strong>見解</strong>：Q2虧損顯示損益平衡點接近營收基線，報價回落即回微利或虧損。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><h3 id="空頭風險一-記憶體報價反轉的營收斷崖" tabindex="-1">空頭風險一：記憶體報價反轉的營收斷崖 <a class="header-anchor" href="#空頭風險一-記憶體報價反轉的營收斷崖" aria-label="Permalink to &quot;空頭風險一：記憶體報價反轉的營收斷崖&quot;">​</a></h3><p>凌航 2025 年營收暴增 135%，本質是「量價齊揚」的順風行情。DRAM 報價在 2025 年下半年大幅上揚，帶動毛利率從 3.6% 飆至 19.12%。然而，國際大廠（Samsung、SK Hynix、Micron）新產能預計 2027 年後開出，但在那之前，若 AI 需求不如預期或終端庫存修正啟動，DRAM 報價可能在 2026 下半年快速回落。凌航 2025Q2 在營收 17.39 億時即虧損，若報價回落導致毛利率回到 4-5% 區間，以目前的營收規模推估，公司將面臨單季虧損 1-2 億的壓力。<strong>最極端情境</strong>：若 DRAM 報價回落 30%，凌航 2026 年 EPS 可能從 2025 年的 4.83 元骤降至 1 元以下。</p><h3 id="空頭風險二-b2g-標案集中度與出貨節奏風險" tabindex="-1">空頭風險二：B2G 標案集中度與出貨節奏風險 <a class="header-anchor" href="#空頭風險二-b2g-標案集中度與出貨節奏風險" aria-label="Permalink to &quot;空頭風險二：B2G 標案集中度與出貨節奏風險&quot;">​</a></h3><p>47% 營收來自系統整合與政府標案，此類收入具有「一次性、大額、集中出貨」的特質。2025 年 12 月營收 11.76 億（占全年 15%）即為典型的標案集中出貨。若 2026 年重要標案延遲、流標或預算縮減，單一月份營收可能驟降 50% 以上。此外，印度政府專案等海外標案還面臨匯率風險與地緣政治變數。<strong>核心隱憂</strong>：凌航未披露前五大客戶各自的營收佔比，若單一客戶超過 15%，將構成嚴重的營收集中度風險。</p><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (月營收)</strong>：OK。2025/05-2026/03 共 11 個月數據，MoM 波動率 30.3% 由原始數據計算得出。</li><li><strong>FinMind (季報財務)</strong>：OK。2024Q2-2025FY 之營收、毛利、淨利數據完整。2025Q4 毛利率 19.12% 由財務數據交叉驗證。</li><li><strong>yfinance</strong>：未使用（3135 上市時間短，yfinance 資料不完整）。</li><li><strong>年報/法說會</strong>：3135 無年報 PDF（2025 年上市），使用上市前業績發表會（2025/06/15）及公開資訊觀測站資料。</li><li><strong>關鍵核對碼</strong>： <ul><li>「2025年累計營收 77.04 億，YoY +135%」——鉅亨網、CMoney 多源交叉驗證</li><li>「2025Q4 毛利率 19.12%」——優分析/StatementDog 與 FinMind 財務數據吻合</li><li>「2026Q1 累計營收 39.58 億，YoY +177.96%」——公司月營收公告（1月15.46億 + 2月9.81億 + 3月14.30億）</li><li>「DRAM 佔 68%，Flash 佔 31%」——公司上市前業績發表會簡報</li><li>「客群：SI/B2G 47%、電競 46%、工控 7%」——CMoney/Line Today 報導</li></ul></li></ul>',24)])])}const _=t(r,[["render",e]]);export{u as __pageData,_ as default};
